/// @ts-nocheck
/**
 * Service Worker for DevMem AI — pre-caches ALL build assets (JS, CSS,
 * WASM, workers, fonts) using a build-time manifest so that the very
 * first offline refresh works.
 *
 * Install: fetches /precache-manifest.json (generated by Vite plugin)
 * and caches every listed asset plus the app shell.
 *
 * Fetch: network-first for all requests, falling back to cache offline.
 */

const CACHE_PREFIX = 'devmem-'

self.addEventListener('install', (event) => {
  event.waitUntil(
    fetch('/precache-manifest.json')
      .then((res) => res.json())
      .then(({ version, assets }) => {
        self.__CACHE_NAME = version
        const urls = ['/', '/index.html', '/manifest.json', '/favicon.svg', ...assets]
        return caches.open(version).then((cache) => cache.addAll(urls))
      })
  )
  self.skipWaiting()
})

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((names) =>
      Promise.all(
        names
          .filter((n) => n.startsWith(CACHE_PREFIX) && n !== self.__CACHE_NAME)
          .map((n) => caches.delete(n))
      )
    )
  )
  self.clients.claim()
})

/**
 * Helper: open the current versioned cache.
 */
function openCurrentCache() {
  return caches.keys().then((names) => {
    const name = names.find((n) => n.startsWith(CACHE_PREFIX))
    return name ? caches.open(name) : null
  })
}

self.addEventListener('fetch', (event) => {
  const { request } = event
  const url = new URL(request.url)

  // Skip non-GET, cross-origin, and Edge Function requests
  if (request.method !== 'GET') return
  if (url.origin !== self.location.origin) return
  if (url.pathname.startsWith('/functions/')) return

  // Navigation: network-first, fallback to cached index.html (SPA)
  if (request.mode === 'navigate') {
    event.respondWith(
      fetch(request)
        .then((response) => {
          const clone = response.clone()
          openCurrentCache().then((cache) => {
            if (cache) cache.put(request, clone)
          })
          return response
        })
        .catch(() => caches.match('/index.html'))
    )
    return
  }

  // All other same-origin: network-first, cache fallback
  event.respondWith(
    fetch(request)
      .then((response) => {
        if (response.ok) {
          const clone = response.clone()
          openCurrentCache().then((cache) => {
            if (cache) cache.put(request, clone)
          })
        }
        return response
      })
      .catch(() =>
        caches.match(request).then(
          (cached) => cached || new Response('', { status: 503, statusText: 'Offline' })
        )
      )
  )
})
